// ──────────────────────────────────────────────
// PARSE AI response and route to correct operation
// ──────────────────────────────────────────────
const aiResponse = $input.first().json;
const slackData = $node['Parse Slack Payload'].json;

let parsed;
try {
  const content = aiResponse.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    operation: 'error',
    params: {},
    human_summary: 'Could not understand command: ' + slackData.userCommand
  };
}

return [{
  json: {
    ...slackData,
    ...parsed
  }
}];

// ──────────────────────────────────────────────
// FORMAT Slack Block Kit response
// ──────────────────────────────────────────────
const result = $input.first().json;
const context = $node['Parse AI Decision'].json;
const operation = context.operation;

let responseText = '';

if (operation === 'update_status') {
  const updated = Array.isArray(result) ? result : [result];
  if (updated.length > 0 && updated[0].id) {
    responseText = `✅ *Status Updated*\n• Lead: ${updated[0].name}\n• New Status: \`${context.params.new_status}\`\n• Updated by: <@${context.userId}>`;
  } else {
    responseText = `⚠️ No lead found matching "${context.params.name}"`;
  }
} else if (operation === 'search_leads') {
  const leads = Array.isArray(result) ? result : [];
  if (leads.length === 0) {
    responseText = `🔍 No leads found for "${context.params.value}"`;
  } else {
    const list = leads.slice(0, 5).map((l, i) => 
      `${i+1}. *${l.name}* — ${l.ai_priority || '?'} | ${l.status} | Score: ${l.ai_score || '?'}`
    ).join('\n');
    responseText = `🔍 *Found ${leads.length} lead(s):*\n${list}`;
  }
} else if (operation === 'get_pipeline_stats') {
  const leads = Array.isArray(result) ? result : [];
  const stats = {
    total: leads.length,
    hot: leads.filter(l => l.ai_priority === 'HOT').length,
    warm: leads.filter(l => l.ai_priority === 'WARM').length,
    cold: leads.filter(l => l.ai_priority === 'COLD').length,
    won: leads.filter(l => l.status === 'won').length
  };
  responseText = `📊 *Pipeline Stats:*\n🔥 HOT: ${stats.hot} | 🟡 WARM: ${stats.warm} | 🔵 COLD: ${stats.cold}\n✅ Won: ${stats.won} | 📋 Total: ${stats.total}`;
} else {
  responseText = `❓ ${context.human_summary}\nCommand: \`${context.userCommand}\``;
}

return [{ json: { text: responseText, channelId: context.channelId } }];
